/** @jsxRuntime classic */
/** @jsx jsx */
import React, { useMemo, useRef } from 'react';
import clsx from 'clsx';
import composeRefs from '../../../util/composeRefs';
import { useCssScope } from '../../../config-provider/hooks';
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { jsx } from '@universe-design/stylex/react';
import { useFocus } from '@universe-design/react-input';

import type { StylexProps } from '@universe-design/stylex/react';
import './style/index.less';

export type NativeInputProps = React.ComponentPropsWithoutRef<'input'> & {
  onFocusChange?: (focused: boolean, event: Event) => void;
} & StylexProps;

/**
 * @description 抽离原生input供 Input/Input-number/Select/Date-picker使用，内置对样式的统一处理
 * @internal
 */
const NativeInput = React.forwardRef<HTMLInputElement, NativeInputProps>(function NativeInput(props, ref) {
  const { className, onFocusChange, autoFocus, ...restProps } = props;
  const classNames = clsx(className, useCssScope('native-input')());
  const inputRef = useRef<HTMLInputElement>(null);

  const mergedRef = useMemo(() => composeRefs(ref, inputRef), [ref]);
  useFocus({
    inputRef,
    onFocusChange,
    autoFocus: Boolean(autoFocus),
  });

  return <input ref={mergedRef} className={classNames} {...restProps} />;
});

export default NativeInput;
